          <RagChatbotWorkspace
            chatModel={runtimeState.chatModel}
            isChatAvailable={runtimeState.isChatAvailable}
            nodeVersion={runtimeState.nodeVersion}
            sourceDocument={runtimeState.sourceDocument}
            setupMessage={runtimeState.setupMessage}
          />
        </div>
      </div>
    </main>
  );
}

"use client";

import {
  ArrowClockwiseIcon,
  BookOpenIcon,
  RobotIcon,
  StopIcon,
} from "@phosphor-icons/react";
import {
  Conversation,
  ConversationContent,
  ConversationEmptyState,
  ConversationScrollButton,
} from "@/components/ai-elements/conversation";
import {
  Message,
  MessageContent,
  MessageResponse,
} from "@/components/ai-elements/message";
import {
  PromptInput,
  PromptInputBody,
  PromptInputFooter,
  PromptInputSubmit,
  PromptInputTextarea,
} from "@/components/ai-elements/prompt-input";
import {
  Source,
  Sources,
  SourcesContent,
  SourcesTrigger,
} from "@/components/ai-elements/sources";
import {
  Tool,
  ToolContent,
  ToolHeader,
  ToolInput,
  ToolOutput,
} from "@/components/ai-elements/tool";
import { Badge } from "@/components/ui/badge";
import { Button, buttonVariants } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import Link from "next/link";
import { useMemo } from "react";

import type { ragChatbotSourceDocument } from "@/lib/rag-chatbot/source-document";

import {
  getGroundedSourceKey,
  projectGroundedMessage,
} from "./grounded-response";
import { useRagChatbot } from "./use-rag-chatbot";

export interface RagChatbotWorkspaceProps {
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
  sourceDocument: typeof ragChatbotSourceDocument;
}

export function RagChatbotWorkspace({
  chatModel,
  isChatAvailable,
  nodeVersion,
  sourceDocument,
  setupMessage,
}: RagChatbotWorkspaceProps) {
  const {
    error,
    hasMessages,
    isBusy,
    messages,
    regenerate,
    sendMessage,
    status,
    stop,
  } = useRagChatbot();
  const samplePrompts = useMemo(
    () => [
      "What does the manual say about the NASA logotype?",
      "How should the seal and the logotype be used differently?",
      "Summarize the core visual system described in this manual.",
    ],
    []
  );

  return (
    <div className="grid min-h-[70svh] gap-4 lg:h-full lg:min-h-0 lg:grid-cols-[minmax(0,1fr)_20rem]">
      <section className="flex min-h-[70svh] flex-col border border-foreground/10 bg-background lg:h-full lg:min-h-0">
        {isChatAvailable ? null : (
          <div className="border-foreground/10 border-b px-4 py-3 text-muted-foreground text-xs/relaxed">
            {setupMessage}
          </div>
        )}

        {error ? (
          <div className="border-foreground/10 border-b px-4 py-3 text-destructive text-xs/relaxed">
            {error.message}
          </div>
        ) : null}

        <Conversation className="min-h-0">
          <ConversationContent className="mx-auto flex w-full max-w-3xl flex-1 gap-6 px-4 py-6">
            {hasMessages ? (
              messages.map((message) => {
                const projection = projectGroundedMessage(message);

                return (
                  <Message from={message.role} key={message.id}>
                    <MessageContent
                      className={cn(
                        "space-y-4",
                        message.role === "assistant" ? "max-w-3xl" : "max-w-2xl"
                      )}
                    >
                      {projection.sources.length > 0 ? (
                        <Sources>
                          <SourcesTrigger count={projection.sources.length} />
                          <SourcesContent>
                            {projection.sources.map((source, index) => (
                              <Source
                                href={source.documentUrl}
                                key={getGroundedSourceKey(
                                  message.id,
                                  source,
                                  index
                                )}
                                title={source.citationLabel}
                              >
                                <span className="font-medium">
                                  {source.citationLabel}
                                </span>
                                {source.sectionTitle ? (
                                  <span className="text-muted-foreground">
                                    {source.sectionTitle}
                                  </span>
                                ) : null}
                              </Source>
                            ))}
                          </SourcesContent>
                        </Sources>
                      ) : null}

                      {projection.text ? (
                        <MessageResponse>{projection.text}</MessageResponse>
                      ) : (
                        <p className="text-muted-foreground text-sm">
                          Waiting for visible output.
                        </p>
                      )}

                      {projection.toolParts.map((part) => (
                        <Tool key={part.toolCallId}>
                          {part.type === "dynamic-tool" ? (
                            <ToolHeader
                              state={part.state}
                              title="Knowledge Base Retrieval"
                              toolName={part.toolName}
                              type={part.type}
                            />
                          ) : (
                            <ToolHeader
                              state={part.state}
                              title="Knowledge Base Retrieval"
                              type={part.type}
                            />
                          )}
                          <ToolContent>
                            {part.input ? (
                              <ToolInput input={part.input} />
                            ) : null}
                            <ToolOutput
                              errorText={part.errorText}
                              output={part.output}
                            />
                          </ToolContent>
                        </Tool>
                      ))}
                    </MessageContent>
                  </Message>
                );
              })
            ) : (
              <ConversationEmptyState
                description="Ask about the indexed design manual. Every grounded answer is expected to flow through retrieval."
                icon={<BookOpenIcon className="size-5" />}
                title="Document support workspace is ready"
              />
            )}
          </ConversationContent>
          <ConversationScrollButton />
        </Conversation>

        <div className="border-foreground/10 border-t px-4 py-4">
          <div className="mx-auto w-full max-w-3xl">
            <PromptInput onSubmit={({ text }) => sendMessage({ text })}>
              <PromptInputBody>
                <PromptInputTextarea
                  disabled={!isChatAvailable || isBusy}
                  placeholder="Ask what the manual says, and inspect the retrieval trace underneath the answer."
                />
              </PromptInputBody>
              <PromptInputFooter className="flex items-center justify-between gap-3 border-foreground/10 border-t px-3 py-3">
                <div className="flex flex-wrap items-center gap-2">
                  <Badge variant="outline">RAG</Badge>
                  <Badge variant="outline">pgvector</Badge>
                  <Badge variant="outline">{chatModel}</Badge>
                </div>
                <div className="flex items-center gap-2">
                  {isBusy ? (
                    <Button
                      onClick={stop}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <StopIcon className="size-3.5" />
                      Stop
                    </Button>
                  ) : null}
                  {hasMessages ? (
                    <Button
                      onClick={() => regenerate()}
                      size="sm"
                      type="button"
                      variant="outline"
                    >
                      <ArrowClockwiseIcon className="size-3.5" />
                      Retry
                    </Button>
                  ) : null}
                  <PromptInputSubmit
                    disabled={!isChatAvailable}
                    status={status}
                  />
                </div>
              </PromptInputFooter>
            </PromptInput>

            {hasMessages ? null : (
              <div className="mt-3 flex flex-wrap gap-2">
                {samplePrompts.map((prompt) => (
                  <Button
                    key={prompt}
                    onClick={() => sendMessage({ text: prompt })}
                    size="sm"
                    type="button"
                    variant="outline"
                  >
                    <RobotIcon className="size-3.5" />
                    {prompt}
                  </Button>
                ))}
              </div>
            )}
          </div>
        </div>
      </section>

      <aside className="border border-foreground/10 bg-background p-4 lg:min-h-0 lg:overflow-y-auto">
        <div className="space-y-4">
          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Runtime
            </p>
            <p className="mt-1 font-medium text-sm">{nodeVersion}</p>
          </div>
          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Source document
            </p>
            <p className="mt-1 font-medium text-sm">{sourceDocument.title}</p>
            <p className="mt-1 text-muted-foreground text-sm">
              {sourceDocument.description}
            </p>
            <div className="mt-2 flex flex-wrap gap-2">
              <Link
                className={buttonVariants({ size: "sm", variant: "outline" })}
                href={sourceDocument.documentUrl}
                target="_blank"
              >
                Open PDF
              </Link>
              <Link
                className={buttonVariants({ size: "sm", variant: "outline" })}
                href={sourceDocument.sourcePageUrl}
                target="_blank"
              >
                NASA page
              </Link>
            </div>
          </div>
          <div>
            <p className="text-[11px] text-muted-foreground uppercase tracking-[0.2em]">
              Contract
            </p>
            <p className="mt-1 text-sm">
              The assistant is expected to retrieve evidence first, answer only
              from indexed content, and surface the retrieval trace alongside
              the response.
            </p>
          </div>
        </div>
      </aside>
    </div>
  );
}

"use client";

import { Chat, useChat } from "@ai-sdk/react";
import { DefaultChatTransport, type UIMessage } from "ai";
import { useState } from "react";

export function useRagChatbot() {
  const [chat] = useState(
    () =>
      new Chat<UIMessage>({
        transport: new DefaultChatTransport({
          api: "/api/demos/rag-chatbot",
        }),
      })
  );
  const controller = useChat({ chat });
  const hasMessages = controller.messages.length > 0;
  const isBusy =
    controller.status === "submitted" || controller.status === "streaming";

  return {
    ...controller,
    hasMessages,
    isBusy,
  };
}

import { isToolUIPart, type UIMessage } from "ai";
import type { ToolPart } from "@/components/ai-elements/tool";

export interface GroundedSource {
  citationLabel: string;
  content: string;
  documentUrl: string;
  pageLabel: string | null;
  sectionTitle: string | null;
  similarity: number;
  title: string;
}

export interface GroundedMessageProjection {
  sources: GroundedSource[];
  text: string;
  toolParts: ToolPart[];
}

function isGroundedSource(value: unknown): value is GroundedSource {
  if (!value || typeof value !== "object") {
    return false;
  }

  const source = value as Record<string, unknown>;

  return (
    typeof source.citationLabel === "string" &&
    typeof source.content === "string" &&
    typeof source.documentUrl === "string" &&
    (source.pageLabel === null || typeof source.pageLabel === "string") &&
    (source.sectionTitle === null ||
      typeof source.sectionTitle === "string") &&
    typeof source.similarity === "number" &&
    typeof source.title === "string"
  );
}

function readSourcesFromToolPart(part: ToolPart) {
  if (part.state !== "output-available" || !part.output) {
    return [];
  }

  if (typeof part.output !== "object" || !("sources" in part.output)) {
    return [];
  }

  const { sources } = part.output as { sources?: unknown[] };

  return Array.isArray(sources)
    ? sources.filter((source): source is GroundedSource => isGroundedSource(source))
    : [];
}

export function getGroundedSourceKey(
  messageId: string,
  source: GroundedSource,
  index: number
) {
  return [
    messageId,
    source.citationLabel,
    source.pageLabel ?? "no-page",
    source.sectionTitle ?? "no-section",
    source.content.slice(0, 96),
    index,
  ].join("::");
}

export function projectGroundedMessage(
  message: UIMessage
): GroundedMessageProjection {
  const text = message.parts
    .filter((part) => part.type === "text")
    .map((part) => part.text)
    .join("\n");
  const toolParts = message.parts.filter(isToolUIPart) as ToolPart[];
  const sources = toolParts.flatMap((part) => readSourcesFromToolPart(part));

  return {
    sources,
    text,
    toolParts,
  };
}

"use client";

import { CornerDownLeftIcon, LoaderCircleIcon, SquareIcon } from "lucide-react";
import type {
  ComponentProps,
  FormEvent,
  HTMLAttributes,
  ReactNode,
  TextareaHTMLAttributes,
} from "react";
import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
} from "react";
import { Button } from "@/components/ui/button";
import { Textarea } from "@/components/ui/textarea";
import { cn } from "@/lib/utils";

type PromptStatus = "error" | "ready" | "streaming" | "submitted";

interface PromptInputContextValue {
  setText: (text: string) => void;
  text: string;
}

interface PromptInputMessage {
  text: string;
}

interface PromptInputProps
  extends Omit<HTMLAttributes<HTMLFormElement>, "onSubmit"> {
  children: ReactNode;
  onSubmit: (
    message: PromptInputMessage,
    event: FormEvent<HTMLFormElement>
  ) => void | Promise<void>;
}

interface PromptInputSubmitProps
  extends Omit<ComponentProps<typeof Button>, "children" | "type"> {
  onStop?: () => void;
  status?: PromptStatus;
}

type PromptInputClickEvent = Parameters<
  Exclude<ComponentProps<typeof Button>["onClick"], undefined>
>[0];

const PromptInputContext = createContext<PromptInputContextValue | null>(null);

function usePromptInputContext() {
  const context = useContext(PromptInputContext);

  if (!context) {
    throw new Error(
      "PromptInput components must be used inside <PromptInput>."
    );
  }

  return context;
}

export function PromptInput({
  children,
  className,
  onSubmit,
  ...props
}: PromptInputProps) {
  const [text, setText] = useState("");

  const contextValue = useMemo(
    () => ({
      setText,
      text,
    }),
    [text]
  );

  const handleSubmit = useCallback(
    async (event: FormEvent<HTMLFormElement>) => {
      event.preventDefault();

      const nextText = text.trim();
      if (!nextText) {
        return;
      }

      const result = onSubmit({ text: nextText }, event);

      try {
        await result;
        setText("");
      } catch {
        // Keep the text for retry after a failed submit.
      }
    },
    [onSubmit, text]
  );

  return (
    <PromptInputContext.Provider value={contextValue}>
      <form
        className={cn("w-full", className)}
        onSubmit={handleSubmit}
        {...props}
      >
        {children}
      </form>
    </PromptInputContext.Provider>
  );
}

export function PromptInputBody({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn("grid gap-3", className)} {...props} />;
}

export function PromptInputFooter({
  className,
  ...props
}: HTMLAttributes<HTMLDivElement>) {
  return <div className={cn(className)} {...props} />;
}

export function PromptInputTextarea({
  className,
  disabled,
  onChange,
  ...props
}: TextareaHTMLAttributes<HTMLTextAreaElement>) {
  const context = usePromptInputContext();

  return (
    <Textarea
      className={cn("min-h-16 resize-none", className)}
      disabled={disabled}
      onChange={(event) => {
        context.setText(event.currentTarget.value);
        onChange?.(event);
      }}
      value={context.text}
      {...props}
    />
  );
}

export function PromptInputSubmit({
  className,
  disabled,
  onClick,
  onStop,
  size = "icon",
  status = "ready",
  variant = "default",
  ...props
}: PromptInputSubmitProps) {
  const { text } = usePromptInputContext();
  const isBusy = status === "submitted" || status === "streaming";
  const isDisabled = Boolean(disabled) || (!isBusy && text.trim().length === 0);

  let icon = <CornerDownLeftIcon className="size-4" />;

  if (status === "submitted") {
    icon = <LoaderCircleIcon className="size-4 animate-spin" />;
  } else if (status === "streaming") {
    icon = <SquareIcon className="size-4" />;
  }

  return (
    <Button
      aria-label={isBusy ? "Stop" : "Submit"}
      className={cn(className)}
      disabled={isDisabled}
      onClick={(event: PromptInputClickEvent) => {
        if (isBusy && onStop) {
          event.preventDefault();
          onStop();
          return;
        }

        onClick?.(event);
      }}
      size={size}
      type={isBusy && onStop ? "button" : "submit"}
      variant={variant}
      {...props}
    >
      {icon}
    </Button>
  );
}

import {
  convertToModelMessages,
  stepCountIs,
  streamText,
  tool,
  type UIMessage,
} from "ai";
import { z } from "zod";

import {
  createRagChatbotGateway,
  getRagChatbotConfig,
  getRagChatbotEnv,
  type RagChatbotEnv,
} from "./env";
import { findRelevantContent } from "./retrieval";

const systemPrompt = [
  "You are the rag-chatbot demo for an independent-site document support agent.",
  "Answer only with information grounded in the indexed document knowledge base.",
  "Use the getInformation tool before answering any question about the document.",
  'If the tool returns no relevant evidence, reply exactly with "Sorry, I don\'t know."',
  "When evidence exists, answer concisely and mention the most relevant document section or page when possible.",
  "Do not turn document guidance into legal, trademark, or commercial authorization claims.",
].join(" ");

export async function streamRagChatbot(
  messages: UIMessage[],
  env: RagChatbotEnv = getRagChatbotEnv()
) {
  const gateway = createRagChatbotGateway(env);
  const { chatModel } = getRagChatbotConfig(env);

  const result = streamText({
    model: gateway(chatModel),
    system: systemPrompt,
    messages: await convertToModelMessages(messages),
    stopWhen: stepCountIs(5),
    tools: {
      getInformation: tool({
        description:
          "Retrieve grounded document snippets from the indexed knowledge base to answer the user's question.",
        inputSchema: z.object({
          question: z
            .string()
            .min(1)
            .describe("The user's question about the indexed document."),
        }),
        execute: async ({ question }) => findRelevantContent(question, env),
      }),
    },
  });

  return result.toUIMessageStreamResponse();
}

import { Pool } from "@neondatabase/serverless";
import { drizzle } from "drizzle-orm/neon-serverless";

import {
  getRagChatbotDatabaseConfig,
  getRagChatbotEnv,
  type RagChatbotEnv,
} from "./env";
import {
  ragChatbotEmbeddings,
  ragChatbotResources,
  ragChatbotSchema,
} from "./schema";

function createRagChatbotDatabase(connectionString: string) {
  const client = new Pool({ connectionString });
  const database = drizzle({
    client,
    schema: ragChatbotSchema,
  });

  return { client, database };
}

type RagChatbotDatabase = ReturnType<
  typeof createRagChatbotDatabase
>["database"];

export interface RagChatbotDatabaseModule {
  database: RagChatbotDatabase;
  ragChatbotEmbeddings: typeof ragChatbotEmbeddings;
  ragChatbotResources: typeof ragChatbotResources;
}

let databaseModulePromise: Promise<RagChatbotDatabaseModule> | null = null;

export async function loadRagChatbotDatabase(
  env: RagChatbotEnv = getRagChatbotEnv()
): Promise<RagChatbotDatabaseModule> {
  if (!databaseModulePromise) {
    const { databaseUrl } = getRagChatbotDatabaseConfig(env);
    const { database } = createRagChatbotDatabase(databaseUrl);

    databaseModulePromise = Promise.resolve({
      database,
      ragChatbotEmbeddings,
      ragChatbotResources,
    });
  }

  return databaseModulePromise;
}

import { createGateway } from "ai";
import { getRagChatbotAppEnv } from "./env-source";

const DEFAULT_GATEWAY_BASE_URL = "https://ai-gateway.vercel.sh/v3/ai";
const DEFAULT_CHAT_MODEL = "openai/gpt-4.1-mini";
const DEFAULT_EMBEDDING_MODEL = "openai/text-embedding-3-small";
const MINIMUM_NODE_VERSION = "22.13.0";
const nodeVersionPattern = /^v?(\d+)\.(\d+)\.(\d+)(?:[-+].*)?$/;

interface ParsedNodeVersion {
  major: number;
  minor: number;
  patch: number;
}

export type RagChatbotEnv = Record<string, string | undefined>;

export interface RagChatbotConfig {
  apiKey: string;
  baseURL: string;
  chatModel: string;
  databaseUrl: string | undefined;
  embeddingModel: string;
}

export interface RagChatbotSetupState {
  config: Omit<RagChatbotConfig, "apiKey" | "databaseUrl">;
  isReady: boolean;
  issues: string[];
  nodeVersion: string;
}

function parseNodeVersion(version: string): ParsedNodeVersion {
  const match = nodeVersionPattern.exec(version);
  const major = Number(match?.[1]);
  const minor = Number(match?.[2]);
  const patch = Number(match?.[3]);

  if (![major, minor, patch].every(Number.isInteger)) {
    throw new Error(`Unable to parse Node.js version: "${version}".`);
  }

  return { major, minor, patch };
}

function compareNodeVersions(
  left: ParsedNodeVersion,
  right: ParsedNodeVersion
): number {
  if (left.major !== right.major) {
    return left.major - right.major;
  }

  if (left.minor !== right.minor) {
    return left.minor - right.minor;
  }

  return left.patch - right.patch;
}

function assertSupportedNodeRuntime(version = process.version): void {
  const parsedVersion = parseNodeVersion(version);
  const minimumVersion = parseNodeVersion(MINIMUM_NODE_VERSION);

  if (compareNodeVersions(parsedVersion, minimumVersion) < 0) {
    throw new Error(
      `Node.js ${version} is unsupported. This demo workspace requires Node.js >=${MINIMUM_NODE_VERSION}.`
    );
  }
}

export function getRagChatbotEnv(): RagChatbotEnv {
  return getRagChatbotAppEnv();
}

function readRequiredEnv(env: RagChatbotEnv, name: keyof RagChatbotEnv) {
  const value = env[name];

  if (!value) {
    throw new Error(
      `Missing ${name}. Add it to .env.local before using the RAG chatbot.`
    );
  }

  return value;
}

function resolveRagChatbotEnv(env: RagChatbotEnv = getRagChatbotEnv()) {
  return {
    apiKey: env.AI_GATEWAY_API_KEY,
    baseURL: env.AI_GATEWAY_BASE_URL || DEFAULT_GATEWAY_BASE_URL,
    chatModel: env.AI_GATEWAY_CHAT_MODEL || DEFAULT_CHAT_MODEL,
    databaseUrl: env.DATABASE_URL,
    embeddingModel:
      env.AI_GATEWAY_EMBEDDING_MODEL || DEFAULT_EMBEDDING_MODEL,
  };
}

export function getRagChatbotConfig(
  env: RagChatbotEnv = getRagChatbotEnv()
): RagChatbotConfig {
  assertSupportedNodeRuntime();
  const resolvedEnv = resolveRagChatbotEnv(env);

  return {
    apiKey: readRequiredEnv(env, "AI_GATEWAY_API_KEY"),
    baseURL: resolvedEnv.baseURL,
    chatModel: resolvedEnv.chatModel,
    databaseUrl: resolvedEnv.databaseUrl,
    embeddingModel: resolvedEnv.embeddingModel,
  };
}

export function getRagChatbotDatabaseConfig(
  env: RagChatbotEnv = getRagChatbotEnv()
) {
  const databaseUrl = env.DATABASE_URL;

  if (!databaseUrl) {
    throw new Error(
      "DATABASE_URL is missing. The RAG chatbot requires a writable pgvector database."
    );
  }

  return { databaseUrl };
}

export function getRagChatbotSetupState(
  env: RagChatbotEnv = getRagChatbotEnv()
): RagChatbotSetupState {
  const issues: string[] = [];
  const resolvedEnv = resolveRagChatbotEnv(env);

  try {
    assertSupportedNodeRuntime();
  } catch (error) {
    issues.push(
      error instanceof Error ? error.message : "Unsupported Node.js runtime."
    );
  }

  if (!resolvedEnv.apiKey) {
    issues.push(
      "AI_GATEWAY_API_KEY is missing. The demo can render, but chat requests will fail until it is configured."
    );
  }

  return {
    config: {
      baseURL: resolvedEnv.baseURL,
      chatModel: resolvedEnv.chatModel,
      embeddingModel: resolvedEnv.embeddingModel,
    },
    isReady: issues.length === 0,
    issues,
    nodeVersion: process.version,
  };
}

export function getRagChatbotIndexSetupIssue(
  env: RagChatbotEnv = getRagChatbotEnv()
): string | null {
  if (!env.AI_GATEWAY_API_KEY) {
    return "AI_GATEWAY_API_KEY is missing. Source indexing requires embedding generation through AI Gateway.";
  }

  if (!env.DATABASE_URL) {
    return "DATABASE_URL is missing. Source indexing requires a writable pgvector database.";
  }

  return null;
}

export function createRagChatbotGateway(
  env: RagChatbotEnv = getRagChatbotEnv()
) {
  const { apiKey, baseURL } = getRagChatbotConfig(env);

  return createGateway({
    apiKey,
    baseURL,
  });
}

