import { getDocument } from "pdfjs-dist/legacy/build/pdf.mjs";

export interface ExtractedPdfPage {
  pageNumber: number;
  text: string;
}

export interface RagPdfChunk {
  content: string;
  pageLabel: string;
  sectionTitle: string | null;
}

interface BuildRagPdfChunksOptions {
  maxChunkLength?: number;
}

const defaultMaxChunkLength = 700;
function normalizeExtractedLine(text: string) {
  return text.replace(/\s+/g, " ").replace(/\s+([,.;:!?])/g, "$1").trim();
}

function normalizePageLines(text: string) {
  return text
    .split("\n")
    .map((line) => line.trim())
    .filter((line) => line.length > 0);
}

function deriveSectionTitle(lines: string[]) {
  const candidate = lines[0];

  if (!candidate || candidate.length > 80) {
    return null;
  }

  return candidate;
}

function splitIntoSentences(text: string) {
  return text
    .split(/(?<=[.!?])\s+/)
    .map((sentence) => sentence.trim())
    .filter((sentence) => sentence.length > 0);
}

export function buildRagPdfChunks(
  pages: ExtractedPdfPage[],
  options: BuildRagPdfChunksOptions = {}
): RagPdfChunk[] {
  const maxChunkLength = options.maxChunkLength ?? defaultMaxChunkLength;

  return pages.flatMap((page) => {
    const lines = normalizePageLines(page.text);

    if (lines.length === 0) {
      return [];
    }

    const sectionTitle = deriveSectionTitle(lines);
    const normalizedText = lines.join(" ");
    const sentences = splitIntoSentences(normalizedText);
    const chunks: RagPdfChunk[] = [];
    let currentChunk = "";

    for (const sentence of sentences) {
      const candidate = currentChunk
        ? `${currentChunk} ${sentence}`
        : sentence;

      if (candidate.length <= maxChunkLength || currentChunk.length === 0) {
        currentChunk = candidate;
        continue;
      }

      chunks.push({
        content: currentChunk,
        pageLabel: String(page.pageNumber),
        sectionTitle,
      });
      currentChunk = sentence;
    }

    if (currentChunk.length > 0) {
      chunks.push({
        content: currentChunk,
        pageLabel: String(page.pageNumber),
        sectionTitle,
      });
    }

    return chunks;
  });
}

export async function downloadPdfDocument(
  documentUrl: string,
  download = fetch
): Promise<Uint8Array> {
  const response = await download(documentUrl);

  if (!response.ok) {
    throw new Error(
      `Failed to download the RAG source PDF from ${documentUrl}. Received ${response.status}.`
    );
  }

  return new Uint8Array(await response.arrayBuffer());
}

export async function extractPdfPages(
  pdfBytes: Uint8Array
): Promise<ExtractedPdfPage[]> {
  const pdf = await getDocument({ data: pdfBytes }).promise;
  const pages: ExtractedPdfPage[] = [];

  for (let pageNumber = 1; pageNumber <= pdf.numPages; pageNumber += 1) {
    const page = await pdf.getPage(pageNumber);
    const textContent = await page.getTextContent();
    const lines: string[] = [];
    let currentLine = "";

    for (const item of textContent.items as Array<{
      hasEOL?: boolean;
      str: string;
    }>) {
      const value = normalizeExtractedLine(item.str);

      if (value.length > 0) {
        currentLine = currentLine ? `${currentLine} ${value}` : value;
      }

      if (item.hasEOL) {
        lines.push(normalizeExtractedLine(currentLine));
        currentLine = "";
      }
    }

    if (currentLine.length > 0) {
      lines.push(normalizeExtractedLine(currentLine));
    }

    const text = lines.filter((line) => line.length > 0).join("\n");

    if (text.length > 0) {
      pages.push({
        pageNumber,
        text,
      });
    }
  }

  return pages;
}

import { createHash } from "node:crypto";
import { embedMany } from "ai";
import { count, eq } from "drizzle-orm";

import {
  type RagChatbotDatabaseModule,
  loadRagChatbotDatabase,
} from "./database";
import {
  createRagChatbotGateway,
  getRagChatbotConfig,
  getRagChatbotEnv,
  type RagChatbotEnv,
} from "./env";
import {
  buildRagPdfChunks,
  downloadPdfDocument,
  type ExtractedPdfPage,
  extractPdfPages,
} from "./ingestion";
import { ragChatbotSourceDocument } from "./source-document";

interface IndexRagChatbotSourceDependencies {
  downloadDocument: (documentUrl: string) => Promise<Uint8Array>;
  extractPages: (pdfBytes: Uint8Array) => Promise<ExtractedPdfPage[]>;
  loadDatabase: () => Promise<RagChatbotDatabaseModule>;
}

export interface RagSourceIndexResult {
  chunkCount: number;
  sourceSlug: string;
  status: "already-indexed" | "indexed";
}

function buildDocumentHash(pdfBytes: Uint8Array) {
  return createHash("sha256").update(pdfBytes).digest("hex");
}

function buildEmbeddingRows(
  chunks: ReturnType<typeof buildRagPdfChunks>,
  embeddings: Awaited<ReturnType<typeof embedMany>>["embeddings"],
  resourceId: string
) {
  return chunks.map((chunk, index) => {
    const embedding = embeddings[index];

    if (!embedding) {
      throw new Error(
        `Missing embedding ${index} while indexing ${ragChatbotSourceDocument.slug}.`
      );
    }

    return {
      chunkIndex: index,
      content: chunk.content,
      embedding,
      pageLabel: chunk.pageLabel,
      resourceId,
      sectionTitle: chunk.sectionTitle,
    };
  });
}

export async function indexRagChatbotSource(
  env: RagChatbotEnv = getRagChatbotEnv(),
  dependencies: IndexRagChatbotSourceDependencies = {
    downloadDocument: downloadPdfDocument,
    extractPages: extractPdfPages,
    loadDatabase: loadRagChatbotDatabase,
  }
): Promise<RagSourceIndexResult> {
  const pdfBytes = await dependencies.downloadDocument(
    ragChatbotSourceDocument.documentUrl
  );
  const contentHash = buildDocumentHash(pdfBytes);
  const { database, ragChatbotEmbeddings, ragChatbotResources } =
    await dependencies.loadDatabase();
  const existingResources = await database
    .select({
      contentHash: ragChatbotResources.contentHash,
      id: ragChatbotResources.id,
    })
    .from(ragChatbotResources)
    .where(eq(ragChatbotResources.sourceSlug, ragChatbotSourceDocument.slug))
    .limit(1);
  const existingResource = existingResources[0];

  if (existingResource?.contentHash === contentHash) {
    const chunkCountRows = await database
      .select({ chunkCount: count() })
      .from(ragChatbotEmbeddings)
      .where(eq(ragChatbotEmbeddings.resourceId, existingResource.id));

    return {
      chunkCount: chunkCountRows[0]?.chunkCount ?? 0,
      sourceSlug: ragChatbotSourceDocument.slug,
      status: "already-indexed",
    };
  }

  const pages = await dependencies.extractPages(pdfBytes);
  const chunks = buildRagPdfChunks(pages);

  if (chunks.length === 0) {
    throw new Error(
      `The RAG source PDF at ${ragChatbotSourceDocument.documentUrl} did not produce any indexable text.`
    );
  }

  const gateway = createRagChatbotGateway(env);
  const { embeddingModel } = getRagChatbotConfig(env);
  const { embeddings } = await embedMany({
    model: gateway.embeddingModel(embeddingModel),
    values: chunks.map((chunk) => chunk.content),
  });
  const resourceValues = {
    contentHash,
    description: ragChatbotSourceDocument.description,
    documentUrl: ragChatbotSourceDocument.documentUrl,
    sourcePageUrl: ragChatbotSourceDocument.sourcePageUrl,
    sourceSlug: ragChatbotSourceDocument.slug,
    title: ragChatbotSourceDocument.title,
    updatedAt: new Date(),
  };

  if (existingResource) {
    await database.transaction(async (transaction) => {
      await transaction
        .update(ragChatbotResources)
        .set(resourceValues)
        .where(eq(ragChatbotResources.id, existingResource.id));
      await transaction
        .delete(ragChatbotEmbeddings)
        .where(eq(ragChatbotEmbeddings.resourceId, existingResource.id));
      await transaction
        .insert(ragChatbotEmbeddings)
        .values(buildEmbeddingRows(chunks, embeddings, existingResource.id));
    });
  } else {
    await database.transaction(async (transaction) => {
      const [resource] = await transaction
        .insert(ragChatbotResources)
        .values(resourceValues)
        .returning({ id: ragChatbotResources.id });

      if (!resource) {
        throw new Error(
          "Failed to create the source resource row for the RAG chatbot."
        );
      }

      await transaction
        .insert(ragChatbotEmbeddings)
        .values(buildEmbeddingRows(chunks, embeddings, resource.id));
    });
  }

  return {
    chunkCount: chunks.length,
    sourceSlug: ragChatbotSourceDocument.slug,
    status: "indexed",
  };
}

import { count, eq } from "drizzle-orm";

import {
  type RagChatbotDatabaseModule,
  loadRagChatbotDatabase,
} from "./database";
import { ragChatbotSourceDocument } from "./source-document";

type DemoEnv = Record<string, string | undefined>;

export interface RagKnowledgeBaseStatus {
  indexedResourceCount: number;
  isReady: boolean;
  message: string | null;
  statusLabel: "Index required" | "Ready" | "Setup required";
}

export interface RagKnowledgeBaseStatusDependencies {
  getIndexedResourceCount?: (env: DemoEnv) => Promise<number>;
  loadDatabase?: () => Promise<RagChatbotDatabaseModule>;
}

export function getRagDatabaseSetupIssue(env: DemoEnv): string | null {
  if (env.DATABASE_URL) {
    return null;
  }

  return "DATABASE_URL is missing. The RAG chatbot can render, but chat requests require a preindexed pgvector database.";
}

export function getRagIndexRequiredMessage() {
  return `No preindexed documents are available for the RAG chatbot. Run POST /api/demos/rag-chatbot/index to index ${ragChatbotSourceDocument.title}.`;
}

export async function getIndexedResourceCount(
  env: DemoEnv,
  dependencies: RagKnowledgeBaseStatusDependencies = {}
): Promise<number> {
  if (!env.DATABASE_URL) {
    return 0;
  }

  const loadDatabase = dependencies.loadDatabase ?? loadRagChatbotDatabase;
  const { database, ragChatbotResources } = await loadDatabase();
  const rows = await database
    .select({ resourceCount: count() })
    .from(ragChatbotResources)
    .where(eq(ragChatbotResources.sourceSlug, ragChatbotSourceDocument.slug));

  return rows[0]?.resourceCount ?? 0;
}

export async function getRagKnowledgeBaseStatus(
  env: DemoEnv,
  dependencies: RagKnowledgeBaseStatusDependencies = {}
): Promise<RagKnowledgeBaseStatus> {
  const databaseIssue = getRagDatabaseSetupIssue(env);

  if (databaseIssue) {
    return {
      indexedResourceCount: 0,
      isReady: false,
      message: databaseIssue,
      statusLabel: "Setup required",
    };
  }

  try {
    const indexedResourceCount = dependencies.getIndexedResourceCount
      ? await dependencies.getIndexedResourceCount(env)
      : await getIndexedResourceCount(env, dependencies);

    if (indexedResourceCount === 0) {
      return {
        indexedResourceCount,
        isReady: false,
        message: getRagIndexRequiredMessage(),
        statusLabel: "Index required",
      };
    }

    return {
      indexedResourceCount,
      isReady: true,
      message: null,
      statusLabel: "Ready",
    };
  } catch (error) {
    return {
      indexedResourceCount: 0,
      isReady: false,
      message:
        error instanceof Error
          ? `Failed to inspect the indexed document state. ${error.message}`
          : "Failed to inspect the indexed document state.",
      statusLabel: "Setup required",
    };
  }
}

export async function ensureRagKnowledgeBaseReady(
  env: DemoEnv,
  dependencies: RagKnowledgeBaseStatusDependencies = {}
) {
  const status = await getRagKnowledgeBaseStatus(env, dependencies);

  if (!status.isReady) {
    throw new Error(status.message ?? "The RAG knowledge base is unavailable.");
  }
}

import {
  and,
  cosineDistance,
  desc,
  eq,
  gt,
  sql,
} from "drizzle-orm";

import { embed } from "ai";

import {
  type RagChatbotDatabaseModule,
  loadRagChatbotDatabase,
} from "./database";
import {
  createRagChatbotGateway,
  getRagChatbotConfig,
  getRagChatbotEnv,
  type RagChatbotEnv,
} from "./env";
import {
  ensureRagKnowledgeBaseReady,
} from "./knowledge-base-status";
import { ragChatbotSourceDocument } from "./source-document";

const matchLimit = 4;
const minimumSimilarity = 0.55;

export interface RetrievedRagContent {
  content: string;
  documentUrl: string;
  pageLabel: string | null;
  sectionTitle: string | null;
  similarity: number;
  title: string;
}

export interface RagToolSource {
  citationLabel: string;
  content: string;
  documentUrl: string;
  pageLabel: string | null;
  sectionTitle: string | null;
  similarity: number;
  title: string;
}

export interface RagToolResult {
  answerable: boolean;
  message: string;
  sources: RagToolSource[];
}

interface FindRelevantContentDependencies {
  ensureKnowledgeBaseReady?: (env: RagChatbotEnv) => Promise<void>;
  findMatches?: (input: {
    queryEmbedding: number[];
    sourceSlug: string;
  }) => Promise<RetrievedRagContent[]>;
  generateEmbedding: (value: string, env: RagChatbotEnv) => Promise<number[]>;
  loadDatabase?: () => Promise<RagChatbotDatabaseModule>;
}

function createCitationLabel(source: RetrievedRagContent): string {
  return source.pageLabel
    ? `${source.title}, p. ${source.pageLabel}`
    : source.title;
}

export function createRagToolResult(
  matches: RetrievedRagContent[]
): RagToolResult {
  if (matches.length === 0) {
    return {
      answerable: false,
      message:
        "No relevant indexed document snippets were found for this question.",
      sources: [],
    };
  }

  return {
    answerable: true,
    message: `Found ${matches.length} relevant indexed document ${
      matches.length === 1 ? "snippet" : "snippets"
    }.`,
    sources: matches.map((match) => ({
      citationLabel: createCitationLabel(match),
      content: match.content,
      documentUrl: match.documentUrl,
      pageLabel: match.pageLabel,
      sectionTitle: match.sectionTitle,
      similarity: match.similarity,
      title: match.title,
    })),
  };
}

async function findMatchesForSource(
  input: {
    queryEmbedding: number[];
    sourceSlug: string;
  },
  loadDatabase: () => Promise<RagChatbotDatabaseModule>
): Promise<RetrievedRagContent[]> {
  const { database, ragChatbotEmbeddings, ragChatbotResources } =
    await loadDatabase();
  const similarity = sql<number>`1 - (${cosineDistance(
    ragChatbotEmbeddings.embedding,
    input.queryEmbedding
  )})`;

  return database
    .select({
      content: ragChatbotEmbeddings.content,
      documentUrl: ragChatbotResources.documentUrl,
      pageLabel: ragChatbotEmbeddings.pageLabel,
      sectionTitle: ragChatbotEmbeddings.sectionTitle,
      similarity,
      title: ragChatbotResources.title,
    })
    .from(ragChatbotEmbeddings)
    .innerJoin(
      ragChatbotResources,
      eq(ragChatbotEmbeddings.resourceId, ragChatbotResources.id)
    )
    .where(
      and(
        eq(ragChatbotResources.sourceSlug, input.sourceSlug),
        gt(similarity, minimumSimilarity)
      )
    )
    .orderBy((table) => desc(table.similarity))
    .limit(matchLimit);
}

export async function generateRagEmbedding(
  value: string,
  env: RagChatbotEnv = getRagChatbotEnv()
): Promise<number[]> {
  const gateway = createRagChatbotGateway(env);
  const normalizedValue = value.replaceAll("\n", " ").trim();
  const { embeddingModel } = getRagChatbotConfig(env);
  const { embedding } = await embed({
    model: gateway.embeddingModel(embeddingModel),
    value: normalizedValue,
  });

  return embedding;
}

export async function findRelevantContent(
  userQuery: string,
  env: RagChatbotEnv = getRagChatbotEnv(),
  dependencies: FindRelevantContentDependencies = {
    generateEmbedding: generateRagEmbedding,
  }
): Promise<RagToolResult> {
  const normalizedQuery = userQuery.trim();

  if (normalizedQuery.length === 0) {
    return createRagToolResult([]);
  }

  const sourceSlug = ragChatbotSourceDocument.slug;
  const loadDatabase = dependencies.loadDatabase ?? loadRagChatbotDatabase;
  const ensureKnowledgeBaseReady =
    dependencies.ensureKnowledgeBaseReady ??
    ((nextEnv: RagChatbotEnv) =>
      ensureRagKnowledgeBaseReady(nextEnv, {
        loadDatabase: loadDatabase as never,
      }));
  const findMatches =
    dependencies.findMatches ??
    ((input: { queryEmbedding: number[]; sourceSlug: string }) =>
      findMatchesForSource(input, loadDatabase));

  await ensureKnowledgeBaseReady(env);

  const queryEmbedding = await dependencies.generateEmbedding(
    normalizedQuery,
    env
  );
  const matches = await findMatches({
    queryEmbedding,
    sourceSlug,
  });

  return createRagToolResult(matches);
}

import { type UIMessage, validateUIMessages } from "ai";

import { streamRagChatbot } from "./chat";
import {
  getRagChatbotEnv,
  getRagChatbotSetupState,
  type RagChatbotEnv,
} from "./env";
import {
  getRagKnowledgeBaseStatus,
  type RagKnowledgeBaseStatus,
} from "./knowledge-base-status";
import { ragChatbotSourceDocument } from "./source-document";

interface RagChatbotRequestBody {
  messages?: UIMessage[];
}

export interface RagChatbotRuntimeState {
  chatModel: string;
  isChatAvailable: boolean;
  nodeVersion: string;
  setupMessage: string | null;
  sourceDocument: typeof ragChatbotSourceDocument;
  statusLabel: "Index required" | "Ready" | "Setup required";
}

export interface RagChatbotRuntimeDependencies {
  getKnowledgeBaseStatus: (
    env: RagChatbotEnv
  ) => Promise<RagKnowledgeBaseStatus>;
}

interface RagChatbotRequestDependencies extends RagChatbotRuntimeDependencies {
  streamRagChatbot: (
    messages: UIMessage[],
    env: RagChatbotEnv
  ) => Promise<Response>;
}

const invalidMessagesError = 'Expected a JSON body with a "messages" array.';
const invalidUiMessagesError =
  'Expected each "messages" entry to match the UIMessage format.';
const malformedJsonError = "Expected a valid JSON request body.";

export async function getRagChatbotRuntimeState(
  env: RagChatbotEnv = getRagChatbotEnv(),
  dependencies: RagChatbotRuntimeDependencies = {
    getKnowledgeBaseStatus: getRagKnowledgeBaseStatus,
  }
): Promise<RagChatbotRuntimeState> {
  const gatewaySetup = getRagChatbotSetupState(env);

  if (gatewaySetup.issues.length > 0) {
    return {
      chatModel: gatewaySetup.config.chatModel,
      isChatAvailable: false,
      nodeVersion: gatewaySetup.nodeVersion,
      sourceDocument: ragChatbotSourceDocument,
      setupMessage: gatewaySetup.issues.join(" "),
      statusLabel: "Setup required",
    };
  }

  const knowledgeBaseStatus = await dependencies.getKnowledgeBaseStatus(env);

  return {
    chatModel: gatewaySetup.config.chatModel,
    isChatAvailable: knowledgeBaseStatus.isReady,
    nodeVersion: gatewaySetup.nodeVersion,
    sourceDocument: ragChatbotSourceDocument,
    setupMessage: knowledgeBaseStatus.message,
    statusLabel: knowledgeBaseStatus.statusLabel,
  };
}

async function readRagChatbotMessages(body: unknown): Promise<UIMessage[]> {
  const { messages } = (body ?? {}) as RagChatbotRequestBody;

  if (!Array.isArray(messages)) {
    throw new Error(invalidMessagesError);
  }

  try {
    return await validateUIMessages({ messages });
  } catch {
    throw new Error(invalidUiMessagesError);
  }
}

export async function handleRagChatbotRequest(
  request: Request,
  env: RagChatbotEnv = getRagChatbotEnv(),
  dependencies: RagChatbotRequestDependencies = {
    getKnowledgeBaseStatus: getRagKnowledgeBaseStatus,
    streamRagChatbot,
  }
) {
  const runtimeState = await getRagChatbotRuntimeState(env, dependencies);

  if (!runtimeState.isChatAvailable) {
    return Response.json(
      {
        error: runtimeState.setupMessage,
      },
      { status: 500 }
    );
  }

  let messages: UIMessage[];

  try {
    messages = await readRagChatbotMessages(await request.json());
  } catch (error) {
    if (error instanceof SyntaxError) {
      return Response.json(
        {
          error: malformedJsonError,
        },
        { status: 400 }
      );
    }

    if (
      error instanceof Error &&
      [invalidMessagesError, invalidUiMessagesError].includes(error.message)
    ) {
      return Response.json(
        {
          error: error.message,
        },
        { status: 400 }
      );
    }

    throw error;
  }

  return dependencies.streamRagChatbot(messages, env);
}

import {
  index,
  integer,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
  vector,
} from "drizzle-orm/pg-core";

export const ragChatbotResources = pgTable(
  "rag_chatbot_resources",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    sourceSlug: varchar("source_slug", { length: 191 }).notNull(),
    title: text("title").notNull(),
    sourcePageUrl: text("source_page_url").notNull(),
    documentUrl: text("document_url").notNull(),
    description: text("description"),
    contentHash: varchar("content_hash", { length: 128 }).notNull(),
    createdAt: timestamp("created_at", { withTimezone: true })
      .defaultNow()
      .notNull(),
    updatedAt: timestamp("updated_at", { withTimezone: true })
      .defaultNow()
      .notNull(),
  },
  (table) => ({
    sourceSlugIndex: uniqueIndex("rag_chatbot_resources_source_slug_idx").on(
      table.sourceSlug
    ),
  })
);

export const ragChatbotEmbeddings = pgTable(
  "rag_chatbot_embeddings",
  {
    id: uuid("id").defaultRandom().primaryKey(),
    resourceId: uuid("resource_id")
      .notNull()
      .references(() => ragChatbotResources.id, { onDelete: "cascade" }),
    chunkIndex: integer("chunk_index").notNull(),
    content: text("content").notNull(),
    pageLabel: varchar("page_label", { length: 64 }),
    sectionTitle: text("section_title"),
    embedding: vector("embedding", { dimensions: 1536 }).notNull(),
    createdAt: timestamp("created_at", { withTimezone: true })
      .defaultNow()
      .notNull(),
  },
  (table) => ({
    chunkIndex: uniqueIndex("rag_chatbot_embeddings_resource_chunk_idx").on(
      table.resourceId,
      table.chunkIndex
    ),
    embeddingIndex: index("rag_chatbot_embeddings_embedding_idx").using(
      "hnsw",
      table.embedding.op("vector_cosine_ops")
